const crypto=require('crypto');
const input=$json.body&&typeof $json.body==='object'?{...$json.body}:$json;
const payload=input.payload&&typeof input.payload==='object'&&!Array.isArray(input.payload)?input.payload:{};
const clean=(value)=>value==null?null:String(value).trim();
const project_id=clean(input.project_id||payload.project_id);
const action=String(input.action||payload.action||'run').toLowerCase();
const reviewAction=action==='review';
const episode_id=clean(input.episode_id||payload.episode_id);
const shot_id=clean(input.shot_id||payload.shot_id);
const generation_version=Math.max(1,Number(input.generation_version||payload.generation_version||1));
const allowed=['run','retry','regenerate','review','resume','cancel'];
if(!project_id)throw new Error('PROJECT_NOT_FOUND: project_id is required');
if(!allowed.includes(action))throw new Error('BUSINESS_VALIDATION_FAILED: unsupported image-to-video action');
if(!reviewAction&&!episode_id)throw new Error('EPISODE_NOT_FOUND: episode_id is required');
if(action==='regenerate'&&(!shot_id||generation_version<2))throw new Error('SOURCE_VERSION_MISMATCH: regenerate requires shot_id and a new generation_version');
const review_id=clean(input.review_id||payload.review_id);
const entity_id=clean(input.entity_id||payload.entity_id||payload.shot_video_id);
const review_status=clean(input.review_status||payload.review_status);
if(reviewAction&&(!review_id||!entity_id||!['approved','rejected'].includes(review_status)))throw new Error('BUSINESS_VALIDATION_FAILED: review_id, shot_video entity_id and approved/rejected status are required');
if(reviewAction&&review_status==='rejected'&&!String(input.rejection_reason||payload.rejection_reason||'').trim())throw new Error('BUSINESS_VALIDATION_FAILED: rejected review requires rejection_reason');
const trace_id=clean(input.trace_id||payload.trace_id)||('trace_video_'+crypto.randomUUID());
const entityScope=shot_id||entity_id||episode_id||project_id;
const idempotency_key=[project_id,'image_to_video',entityScope,generation_version].join(':');
const route=reviewAction?'review':action==='cancel'?'cancel':'run';
return [{json:{...input,payload,project_id,episode_id,shot_id,stage:'image_to_video',action,generation_version,test_mode:Boolean(input.test_mode||payload.test_mode),trace_id,task_id:'task_video_'+crypto.randomUUID(),idempotency_key,route,review_id,entity_id,review_status,review_comment:String(input.review_comment||payload.review_comment||''),rejection_reason:String(input.rejection_reason||payload.rejection_reason||''),prompt_adjustment:String(input.prompt_adjustment||payload.prompt_adjustment||''),batch_limit:500,started_ms:Date.now()}}];

const crypto=require('crypto'),x=$json,r=x.request||{},p=r.payload||{};
if(!x.project)throw new Error('PROJECT_NOT_FOUND: project not found');
if(!x.episode)throw new Error('EPISODE_NOT_FOUND: episode does not belong to project');
if(!x.script)throw new Error('EPISODE_SCRIPT_NOT_APPROVED: no approved episode script');
if(!x.storyboard)throw new Error('STORYBOARD_NOT_APPROVED: no approved storyboard for the approved script');
let shots=Array.isArray(x.shots)?x.shots:[];
if(!shots.length)throw new Error(r.shot_id?'SHOT_NOT_FOUND: requested shot is not in the approved storyboard':'STORYBOARD_NOT_APPROVED: approved storyboard has no eligible shots');
const missingImages=shots.filter(s=>!s.storyboard_image_id).map(s=>s.shot_id);
if(missingImages.length)throw new Error('APPROVED_STORYBOARD_IMAGE_NOT_FOUND: '+JSON.stringify({missing_shot_ids:missingImages}));
const versionMismatch=shots.filter(s=>Number(s.source_storyboard_version)!==Number(x.storyboard.version)).map(s=>s.shot_id);
if(versionMismatch.length)throw new Error('SOURCE_VERSION_MISMATCH: '+JSON.stringify({shot_ids:versionMismatch}));
const unlocked=shots.filter(s=>s.assets_locked!==true&&s.assets_locked!=='true').map(s=>s.shot_id);
if(String($env.REQUIRE_LOCKED_ASSETS||'true')==='true'&&unlocked.length)throw new Error('REQUIRED_ASSETS_NOT_LOCKED: '+JSON.stringify({shot_ids:unlocked}));
const effectiveTest=Boolean(r.test_mode||x.project.test_mode);
const limit=effectiveTest?Math.max(1,Math.min(Number($env.TEST_MAX_VIDEO_SHOTS||10),100)):Math.max(1,Math.min(Number(r.batch_limit||500),500));
shots=shots.slice(0,limit);
const provider=effectiveTest?'mock':String(p.provider||$env.VIDEO_PROVIDER||'mock').toLowerCase();
if(!['mock','generic_sync_video','generic_async_video'].includes(provider))throw new Error('UNSUPPORTED_VIDEO_PROVIDER');
const model=String(p.model||$env.VIDEO_MODEL||'mock-image-to-video');
const base=String($env.MEDIA_STORAGE_PATH||'/data/storage').replace(/[\\/]+$/,'');
const publicBase=String($env.MEDIA_PUBLIC_BASE_URL||'http://localhost:8088').replace(/\/$/,'');
const apiBase=String(p.endpoint||$env.VIDEO_API_BASE_URL||'').replace(/\/$/,'');
const resolution=String(p.resolution||$env.VIDEO_DEFAULT_RESOLUTION||'1080x1920');
const match=resolution.match(/^(\d+)x(\d+)$/);
if(!match)throw new Error('VIDEO_PROVIDER_INVALID_RESPONSE: invalid VIDEO_DEFAULT_RESOLUTION');
const width=Number(match[1]),height=Number(match[2]),fps=Number(p.fps||$env.VIDEO_DEFAULT_FPS||24);
const toPublic=(value)=>{const v=String(value||'');if(v.startsWith(base+'/'))return publicBase+'/'+v.slice(base.length+1).replace(/^\/+/, '');return v;};
return shots.map(s=>{
  const currentVersion=Number(s.current_video_version||0);
  if(r.action==='regenerate'&&s.current_video_id&&s.current_video_review_status==='approved')throw new Error('SHOT_VIDEO_ALREADY_APPROVED: approved current video cannot be overwritten');
  if(r.action==='regenerate'&&Number(r.generation_version)<=currentVersion)throw new Error('SOURCE_VERSION_MISMATCH: regeneration version must exceed current video version');
  const existingBusy=s.current_task_id&&['submitting','processing','succeeded'].includes(String(s.current_task_status));
  const alreadySucceeded=s.current_video_id&&s.current_video_status==='succeeded';
  if((alreadySucceeded&&['run','resume'].includes(r.action))||existingBusy){
    return {json:{...r,effective_test_mode:effectiveTest,batch_limit:limit,route:'skip',shot:s,task_id_existing:s.current_task_id||null,skip_reason:alreadySucceeded?'already_succeeded':'task_already_active'}};
  }
  const rawImageRef=String(s.image_storage_url||s.image_url||'');
  const imageRef=provider==='mock'&&rawImageRef.startsWith(base+'/')?rawImageRef:toPublic(rawImageRef);
  if(!imageRef||/^data:/i.test(imageRef))throw new Error('REFERENCE_IMAGE_NOT_ACCESSIBLE: approved frame has no safe URL or storage path');
  const adjustment=String(p.prompt_adjustment||r.prompt_adjustment||'').trim();
  const videoPrompt=[
    s.video_prompt_base,s.image_prompt,'动作：'+String(s.action_description||''),
    '镜头运动：'+String(s.camera_motion||''),'构图：'+String(s.composition||''),
    adjustment?'调整：'+adjustment:'',
    '保持人物、服装、场景与参考帧一致；无字幕、无文字、无水印、无Logo'
  ].filter(Boolean).join('。');
  const negativePrompt=[
    s.negative_prompt_base,s.image_negative_prompt,
    '人物变形，换脸，额外人物，闪烁，抖动，文字，字幕，水印，Logo'
  ].filter(Boolean).join('，');
  const promptHash=crypto.createHash('sha256').update(videoPrompt+'\n'+negativePrompt).digest('hex');
  const keyHash=crypto.createHash('sha256').update([
    r.project_id,r.episode_id,s.shot_id,s.storyboard_image_id,s.image_generation_version,
    r.generation_version,provider,model,promptHash
  ].join(':')).digest('hex');
  const task_id='vtask_'+keyHash.slice(0,24);
  const idempotency_key='video_'+keyHash;
  const claim_token='claim_'+keyHash.slice(0,40);
  const duration=Math.max(1,Math.min(Number(s.duration_seconds||$env.VIDEO_DEFAULT_DURATION_SECONDS||5),30));
  const aspect=String(p.aspect_ratio||$env.VIDEO_DEFAULT_ASPECT_RATIO||'9:16');
  const endpoint=provider==='mock'?'':(apiBase?(apiBase.endsWith('/generate')?apiBase:apiBase+'/generate'):'');
  const request_payload={
    model,provider,prompt:videoPrompt,negative_prompt:negativePrompt,image_url:imageRef,
    reference_asset_ids:Array.isArray(s.reference_asset_ids)?s.reference_asset_ids:[],
    duration_seconds:duration,aspect_ratio:aspect,resolution,width,height,fps,expected_audio:String($env.VIDEO_USE_GENERATED_AUDIO||'false').toLowerCase()==='true',
    storyboard_id:s.storyboard_id,storyboard_version:s.storyboard_version,
    storyboard_image_id:s.storyboard_image_id,
    source_image_generation_version:Number(s.image_generation_version),
    shot_id:s.shot_id,camera_motion:s.camera_motion||'',action_description:s.action_description||'',
    mock_async:Boolean(p.mock_async),simulate:p.simulate||null
  };
  const seed=Number.parseInt(keyHash.slice(0,8),16);
  const shot_video_id='video_'+crypto.createHash('sha1').update(s.shot_id+':'+r.generation_version).digest('hex').slice(0,20);
  return {json:{...r,effective_test_mode:effectiveTest,batch_limit:limit,route:'submit',shot:s,
    provider,model,endpoint,task_id,idempotency_key,claim_token,
    storyboard_image_id:s.storyboard_image_id,shot_video_id,
    video_prompt:videoPrompt,negative_prompt:negativePrompt,reference_image_url:imageRef,
    reference_asset_ids:request_payload.reference_asset_ids,request_payload,seed,
    duration_seconds:duration,aspect_ratio:aspect,width,height,fps,
    max_poll_count:Number($env.VIDEO_MAX_POLL_COUNT||60),
    max_retries:Number($env.VIDEO_MAX_RETRIES||3),
    timeout_ms:Number($env.VIDEO_REQUEST_TIMEOUT_SECONDS||180)*1000,
    poll_interval_seconds:Number($env.VIDEO_POLL_INTERVAL_SECONDS||15),
    regenerate:['retry','regenerate'].includes(r.action)}};
});

const ctx=$('Loop Video Shots').item.json,out=$json||{},data=out.data&&typeof out.data==='object'?out.data:{};
const success=out.success===true&&['processing','succeeded'].includes(String(out.status));
const error=out.error||($json.error?{code:'VIDEO_PROVIDER_FAILED',message:String($json.error.message||$json.error),retryable:true}:null);
return [{json:{...ctx,adapter_success:success,adapter_status:String(out.status||'failed'),
  provider_task_id:data.provider_task_id||null,provider_video_url:data.video_url||null,
  provider_mime_type:data.mime_type||null,provider_duration:Number(data.duration_seconds||0)||null,
  placeholder_status:success?'processing':'failed',placeholder_qc_status:success?'pending':'failed',
  adapter_error:error,adapter_response:{success,status:String(out.status||'failed'),
    task_id:data.task_id||out.task_id||ctx.task_id,provider:ctx.provider,
    provider_task_id:data.provider_task_id||null,video_url:data.video_url||null,error}}}];

const r=$('Validate Image to Video Request').first().json,s=$json;
const required=Number(s.required_count||0),approved=Number(s.approved_count||0);
const active=Number(s.active_count||0),failed=Number(s.failed_count||0),missing=Number(s.missing_count||0);
const allReady=required>0&&approved===required;
const ok=required>0&&failed===0&&missing===0;
const audioDone=s.audio_done===true||s.audio_done==='true';
const fullDone=allReady&&audioDone;
const audioStages=['voice_audio','voice_profiles_created','voice_profile_review','voice_profiles_locked','tts_processing','dialogue_audio_generated','audio_processing','audio_review','audio_ready','audio_plan_completed'];
let nextStage,nextStatus;
if(fullDone){nextStage='stage_4_completed';nextStatus='stage_4_completed';}
else if(!ok){nextStage='stage_4_failed';nextStatus='stage_4_failed';}
else if(allReady&&audioStages.includes(s.project_current_stage)){nextStage=s.project_current_stage;nextStatus=s.project_status;}
else if(allReady){nextStage='shot_videos_approved';nextStatus='running';}
else if(audioStages.includes(s.project_current_stage)){nextStage=s.project_current_stage;nextStatus=s.project_status;}
else{nextStage='video_processing';nextStatus='video_processing';}
const status=fullDone?'stage_4_completed':allReady?'shot_videos_approved':ok?'video_tasks_submitted':'stage_4_failed';
const response={success:ok,project_id:r.project_id,episode_id:r.episode_id,shot_id:r.shot_id,trace_id:r.trace_id,stage:'image_to_video',status,
  data_ref:{entity_type:r.shot_id?'shot_video_task':'video_task_batch',entity_id:r.shot_id||('videos_'+r.episode_id+'_v'+r.generation_version)},
  metrics:{duration_ms:Date.now()-r.started_ms,required_count:required,approved_count:approved,active_count:active,failed_count:failed,missing_count:missing,generation_version:r.generation_version,estimated_cost:0},
  error:ok?null:{code:'PARTIAL_SAVE_REQUIRES_RECOVERY',message:'one or more video tasks failed or were not persisted',retryable:true}};
return [{json:{response,key:r.idempotency_key,workflow_status:ok?'completed':'failed',
  error_code:ok?null:'PARTIAL_SAVE_REQUIRES_RECOVERY',
  error_message:ok?null:response.error.message,next_stage:nextStage,next_status:nextStatus,
  project_id:r.project_id}}];

let r={};try{r=$('Validate Image to Video Request').first().json||{};}catch{}
const raw=String($json.error?.message||$json.message||'image-to-video workflow failed');
const message=raw.replace(/Bearer\s+\S+/gi,'Bearer [REDACTED]').replace(/([?&](?:key|token|signature)=)[^&\s]+/gi,'$1[REDACTED]').slice(0,2000);
const known=['PROJECT_NOT_FOUND','EPISODE_NOT_FOUND','EPISODE_SCRIPT_NOT_APPROVED','STORYBOARD_NOT_APPROVED','SHOT_NOT_FOUND','APPROVED_STORYBOARD_IMAGE_NOT_FOUND','REQUIRED_ASSETS_NOT_LOCKED','SOURCE_VERSION_MISMATCH','SHOT_VIDEO_ALREADY_APPROVED','REFERENCE_IMAGE_NOT_ACCESSIBLE','UNSUPPORTED_VIDEO_PROVIDER','DUPLICATE_VIDEO_TASK_RUNNING','VIDEO_PROVIDER_INVALID_RESPONSE','VIDEO_PROVIDER_FAILED','DATABASE_WRITE_FAILED'];
const code=known.find(k=>message.includes(k))||(/postgres|database|relation|column/i.test(message)?'DATABASE_WRITE_FAILED':'VIDEO_PROVIDER_FAILED');
let details={};const start=message.indexOf('{');if(start>=0){try{details=JSON.parse(message.slice(start));}catch{}}
return [{json:{project_id:r.project_id||$json.project_id||null,episode_id:r.episode_id||$json.episode_id||null,
  shot_id:r.shot_id||$json.shot_id||null,trace_id:r.trace_id||$json.trace_id||null,
  task_id:r.task_id||null,idempotency_key:r.idempotency_key||null,action:r.action||'run',
  generation_version:Number(r.generation_version||1),stage:'image_to_video',
  error:{code,message,retryable:/429|timeout|network|5\d\d|DATABASE_WRITE_FAILED/i.test(message),details}}}];
